-- Authentic credential-free Stock Desk v0.5.0 database fixture.
-- Generated by upgrading an empty SQLite database through Alembic revision
-- 0009_analysis_model_configs, then inserting representative durable task data.
-- The installed current application must migrate this to 0010_parent_active_retry.
BEGIN TRANSACTION;
CREATE TABLE alembic_version (
	version_num VARCHAR(32) NOT NULL,
	CONSTRAINT alembic_version_pkc PRIMARY KEY (version_num)
);
INSERT INTO "alembic_version" VALUES('0009_analysis_model_configs');
CREATE TABLE analysis_attempt (
	run_id VARCHAR(36) NOT NULL,
	role VARCHAR(32) NOT NULL,
	attempt_no INTEGER NOT NULL,
	status VARCHAR(16) NOT NULL,
	provider VARCHAR(64),
	model VARCHAR(256),
	request_hash VARCHAR(71),
	error_json TEXT,
	retryable BOOLEAN,
	backoff_seconds FLOAT,
	template_version VARCHAR(64),
	template_hash VARCHAR(71),
	usage_json TEXT,
	started_at DATETIME NOT NULL,
	finished_at DATETIME,
	PRIMARY KEY (run_id, role, attempt_no),
	CONSTRAINT ck_analysis_attempt_no CHECK (attempt_no BETWEEN 1 AND 6),
	CONSTRAINT ck_analysis_attempt_status CHECK (status IN ('running','succeeded','failed','interrupted','cancelled')),
	CONSTRAINT ck_analysis_attempt_request_hash CHECK (request_hash IS NULL OR (length(request_hash) = 71 AND substr(request_hash, 1, 7) = 'sha256:')),
	CONSTRAINT ck_analysis_attempt_error_json CHECK (error_json IS NULL OR json_valid(error_json) = 1 AND json_type(error_json) = 'object' AND length(CAST(error_json AS BLOB)) <= 16384),
	CONSTRAINT ck_analysis_attempt_backoff CHECK (backoff_seconds IS NULL OR backoff_seconds >= 0),
	CONSTRAINT ck_analysis_attempt_template_hash CHECK (template_hash IS NULL OR (length(template_hash) = 71 AND substr(template_hash, 1, 7) = 'sha256:')),
	CONSTRAINT ck_analysis_attempt_usage_json CHECK (usage_json IS NULL OR json_valid(usage_json) = 1 AND json_type(usage_json) = 'object' AND length(CAST(usage_json AS BLOB)) <= 16384),
	CONSTRAINT ck_analysis_attempt_state_shape CHECK ((status = 'running' AND error_json IS NULL AND retryable IS NULL AND backoff_seconds IS NULL AND usage_json IS NULL AND finished_at IS NULL) OR (status = 'succeeded' AND error_json IS NULL AND retryable IS NULL AND backoff_seconds IS NULL AND finished_at IS NOT NULL) OR (status = 'failed' AND error_json IS NOT NULL AND retryable IS NOT NULL AND finished_at IS NOT NULL) OR (status = 'interrupted' AND error_json IS NOT NULL AND retryable = 1 AND finished_at IS NOT NULL) OR (status = 'cancelled' AND error_json IS NULL AND retryable IS NULL AND backoff_seconds IS NULL AND finished_at IS NOT NULL)),
	FOREIGN KEY(run_id, role) REFERENCES analysis_stage (run_id, role) ON DELETE CASCADE
);
CREATE TABLE analysis_model_config (
	id VARCHAR(71) NOT NULL,
	display_name VARCHAR(128) NOT NULL,
	provider VARCHAR(32) NOT NULL,
	model VARCHAR(256) NOT NULL,
	public_config_json TEXT NOT NULL,
	public_config_hash VARCHAR(71) NOT NULL,
	secret_reference_id VARCHAR(128),
	supersedes_id VARCHAR(71),
	status VARCHAR(16) NOT NULL,
	revision INTEGER NOT NULL,
	verified_at DATETIME,
	last_tested_at DATETIME,
	error_code VARCHAR(64),
	created_at DATETIME NOT NULL,
	updated_at DATETIME NOT NULL,
	PRIMARY KEY (id),
	CONSTRAINT ck_analysis_model_config_id CHECK (length(id) = 71 AND substr(id, 1, 7) = 'sha256:' AND substr(id, 8) NOT GLOB '*[^0-9a-f]*'),
	CONSTRAINT ck_analysis_model_config_hash_binding CHECK (id = public_config_hash),
	CONSTRAINT ck_analysis_model_config_hash CHECK (length(public_config_hash) = 71 AND substr(public_config_hash, 1, 7) = 'sha256:' AND substr(public_config_hash, 8) NOT GLOB '*[^0-9a-f]*'),
	CONSTRAINT ck_analysis_model_config_json CHECK (json_valid(public_config_json) = 1 AND json_type(public_config_json) = 'object' AND length(CAST(public_config_json AS BLOB)) <= 16384),
	CONSTRAINT ck_analysis_model_config_public_shape CHECK (coalesce(json_type(public_config_json, '$.schema_version'), '') = 'text' AND json_extract(public_config_json, '$.schema_version') = 'analysis-model-public-v1' AND coalesce(json_type(public_config_json, '$.provider'), '') = 'text' AND coalesce(json_type(public_config_json, '$.model'), '') = 'text' AND coalesce(json_type(public_config_json, '$.base_url'), '') = 'text' AND length(json_extract(public_config_json, '$.base_url')) BETWEEN 1 AND 2048 AND coalesce(json_type(public_config_json, '$.temperature'), '') = 'real' AND json_extract(public_config_json, '$.temperature') BETWEEN 0.0 AND 2.0 AND coalesce(json_type(public_config_json, '$.timeout_seconds'), '') = 'real' AND json_extract(public_config_json, '$.timeout_seconds') BETWEEN 1.0 AND 300.0 AND coalesce(json_type(public_config_json, '$.max_output_tokens'), '') = 'integer' AND json_extract(public_config_json, '$.max_output_tokens') BETWEEN 1 AND 65536 AND coalesce(json_type(public_config_json, '$.api_key_configured'), '') IN ('true','false') AND coalesce(json_type(public_config_json, '$.secret_reference_id'), '') IN ('null','text') AND json_type(public_config_json, '$.api_key') IS NULL),
	CONSTRAINT ck_analysis_model_config_provider CHECK (provider IN ('deepseek','openai_compatible','ollama') AND provider = json_extract(public_config_json, '$.provider')),
	CONSTRAINT ck_analysis_model_config_model CHECK (length(model) BETWEEN 1 AND 256 AND model = trim(model) AND model = json_extract(public_config_json, '$.model')),
	CONSTRAINT ck_analysis_model_config_secret_binding CHECK ((secret_reference_id IS NULL AND json_type(public_config_json, '$.secret_reference_id') = 'null' AND json_extract(public_config_json, '$.api_key_configured') = 0) OR (secret_reference_id IS NOT NULL AND secret_reference_id = json_extract(public_config_json, '$.secret_reference_id') AND json_extract(public_config_json, '$.api_key_configured') = 1)),
	CONSTRAINT ck_analysis_model_config_secret_reference CHECK (secret_reference_id IS NULL OR secret_reference_id = 'analysis_model_api_key' OR (length(secret_reference_id) = 55 AND substr(secret_reference_id, 1, 23) = 'analysis_model_api_key_' AND substr(secret_reference_id, 24) NOT GLOB '*[^0-9a-f]*')),
	CONSTRAINT ck_analysis_model_config_supersedes CHECK (supersedes_id IS NULL OR supersedes_id <> id),
	CONSTRAINT ck_analysis_model_config_display_name CHECK (length(display_name) BETWEEN 1 AND 128 AND display_name = trim(display_name) AND instr(display_name, char(0)) = 0 AND instr(display_name, char(1)) = 0 AND instr(display_name, char(2)) = 0 AND instr(display_name, char(3)) = 0 AND instr(display_name, char(4)) = 0 AND instr(display_name, char(5)) = 0 AND instr(display_name, char(6)) = 0 AND instr(display_name, char(7)) = 0 AND instr(display_name, char(8)) = 0 AND instr(display_name, char(9)) = 0 AND instr(display_name, char(10)) = 0 AND instr(display_name, char(11)) = 0 AND instr(display_name, char(12)) = 0 AND instr(display_name, char(13)) = 0 AND instr(display_name, char(14)) = 0 AND instr(display_name, char(15)) = 0 AND instr(display_name, char(16)) = 0 AND instr(display_name, char(17)) = 0 AND instr(display_name, char(18)) = 0 AND instr(display_name, char(19)) = 0 AND instr(display_name, char(20)) = 0 AND instr(display_name, char(21)) = 0 AND instr(display_name, char(22)) = 0 AND instr(display_name, char(23)) = 0 AND instr(display_name, char(24)) = 0 AND instr(display_name, char(25)) = 0 AND instr(display_name, char(26)) = 0 AND instr(display_name, char(27)) = 0 AND instr(display_name, char(28)) = 0 AND instr(display_name, char(29)) = 0 AND instr(display_name, char(30)) = 0 AND instr(display_name, char(31)) = 0 AND instr(display_name, char(127)) = 0),
	CONSTRAINT ck_analysis_model_config_status CHECK (status IN ('unverified','verified','failed','disabled')),
	CONSTRAINT ck_analysis_model_config_error_code CHECK (error_code IS NULL OR (length(error_code) BETWEEN 1 AND 64 AND error_code NOT GLOB '*[^a-z0-9_]*')),
	CONSTRAINT ck_analysis_model_config_revision CHECK (typeof(revision) = 'integer' AND revision >= 0),
	CONSTRAINT ck_analysis_model_config_timestamp_format CHECK ((length(created_at) = 26 AND created_at GLOB '[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9] [0-9][0-9]:[0-9][0-9]:[0-9][0-9].[0-9][0-9][0-9][0-9][0-9][0-9]' AND CAST(substr(created_at, 1, 4) AS INTEGER) BETWEEN 1 AND 9999 AND CAST(substr(created_at, 6, 2) AS INTEGER) BETWEEN 1 AND 12 AND CAST(substr(created_at, 9, 2) AS INTEGER) BETWEEN 1 AND (CASE CAST(substr(created_at, 6, 2) AS INTEGER) WHEN 2 THEN 28 + CASE WHEN ((CAST(substr(created_at, 1, 4) AS INTEGER) % 4 = 0 AND CAST(substr(created_at, 1, 4) AS INTEGER) % 100 <> 0) OR CAST(substr(created_at, 1, 4) AS INTEGER) % 400 = 0) THEN 1 ELSE 0 END WHEN 4 THEN 30 WHEN 6 THEN 30 WHEN 9 THEN 30 WHEN 11 THEN 30 ELSE 31 END) AND CAST(substr(created_at, 12, 2) AS INTEGER) BETWEEN 0 AND 23 AND CAST(substr(created_at, 15, 2) AS INTEGER) BETWEEN 0 AND 59 AND CAST(substr(created_at, 18, 2) AS INTEGER) BETWEEN 0 AND 59) AND (length(updated_at) = 26 AND updated_at GLOB '[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9] [0-9][0-9]:[0-9][0-9]:[0-9][0-9].[0-9][0-9][0-9][0-9][0-9][0-9]' AND CAST(substr(updated_at, 1, 4) AS INTEGER) BETWEEN 1 AND 9999 AND CAST(substr(updated_at, 6, 2) AS INTEGER) BETWEEN 1 AND 12 AND CAST(substr(updated_at, 9, 2) AS INTEGER) BETWEEN 1 AND (CASE CAST(substr(updated_at, 6, 2) AS INTEGER) WHEN 2 THEN 28 + CASE WHEN ((CAST(substr(updated_at, 1, 4) AS INTEGER) % 4 = 0 AND CAST(substr(updated_at, 1, 4) AS INTEGER) % 100 <> 0) OR CAST(substr(updated_at, 1, 4) AS INTEGER) % 400 = 0) THEN 1 ELSE 0 END WHEN 4 THEN 30 WHEN 6 THEN 30 WHEN 9 THEN 30 WHEN 11 THEN 30 ELSE 31 END) AND CAST(substr(updated_at, 12, 2) AS INTEGER) BETWEEN 0 AND 23 AND CAST(substr(updated_at, 15, 2) AS INTEGER) BETWEEN 0 AND 59 AND CAST(substr(updated_at, 18, 2) AS INTEGER) BETWEEN 0 AND 59) AND (verified_at IS NULL OR (length(verified_at) = 26 AND verified_at GLOB '[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9] [0-9][0-9]:[0-9][0-9]:[0-9][0-9].[0-9][0-9][0-9][0-9][0-9][0-9]' AND CAST(substr(verified_at, 1, 4) AS INTEGER) BETWEEN 1 AND 9999 AND CAST(substr(verified_at, 6, 2) AS INTEGER) BETWEEN 1 AND 12 AND CAST(substr(verified_at, 9, 2) AS INTEGER) BETWEEN 1 AND (CASE CAST(substr(verified_at, 6, 2) AS INTEGER) WHEN 2 THEN 28 + CASE WHEN ((CAST(substr(verified_at, 1, 4) AS INTEGER) % 4 = 0 AND CAST(substr(verified_at, 1, 4) AS INTEGER) % 100 <> 0) OR CAST(substr(verified_at, 1, 4) AS INTEGER) % 400 = 0) THEN 1 ELSE 0 END WHEN 4 THEN 30 WHEN 6 THEN 30 WHEN 9 THEN 30 WHEN 11 THEN 30 ELSE 31 END) AND CAST(substr(verified_at, 12, 2) AS INTEGER) BETWEEN 0 AND 23 AND CAST(substr(verified_at, 15, 2) AS INTEGER) BETWEEN 0 AND 59 AND CAST(substr(verified_at, 18, 2) AS INTEGER) BETWEEN 0 AND 59)) AND (last_tested_at IS NULL OR (length(last_tested_at) = 26 AND last_tested_at GLOB '[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9] [0-9][0-9]:[0-9][0-9]:[0-9][0-9].[0-9][0-9][0-9][0-9][0-9][0-9]' AND CAST(substr(last_tested_at, 1, 4) AS INTEGER) BETWEEN 1 AND 9999 AND CAST(substr(last_tested_at, 6, 2) AS INTEGER) BETWEEN 1 AND 12 AND CAST(substr(last_tested_at, 9, 2) AS INTEGER) BETWEEN 1 AND (CASE CAST(substr(last_tested_at, 6, 2) AS INTEGER) WHEN 2 THEN 28 + CASE WHEN ((CAST(substr(last_tested_at, 1, 4) AS INTEGER) % 4 = 0 AND CAST(substr(last_tested_at, 1, 4) AS INTEGER) % 100 <> 0) OR CAST(substr(last_tested_at, 1, 4) AS INTEGER) % 400 = 0) THEN 1 ELSE 0 END WHEN 4 THEN 30 WHEN 6 THEN 30 WHEN 9 THEN 30 WHEN 11 THEN 30 ELSE 31 END) AND CAST(substr(last_tested_at, 12, 2) AS INTEGER) BETWEEN 0 AND 23 AND CAST(substr(last_tested_at, 15, 2) AS INTEGER) BETWEEN 0 AND 59 AND CAST(substr(last_tested_at, 18, 2) AS INTEGER) BETWEEN 0 AND 59))),
	CONSTRAINT ck_analysis_model_config_timestamp_order CHECK (updated_at >= created_at AND (verified_at IS NULL OR (verified_at >= created_at AND verified_at <= updated_at)) AND (last_tested_at IS NULL OR (last_tested_at >= created_at AND last_tested_at <= updated_at))),
	CONSTRAINT ck_analysis_model_config_state_shape CHECK ((status = 'unverified' AND verified_at IS NULL AND last_tested_at IS NULL AND error_code IS NULL) OR (status = 'verified' AND verified_at IS NOT NULL AND last_tested_at IS NOT NULL AND verified_at = last_tested_at AND error_code IS NULL) OR (status = 'failed' AND verified_at IS NULL AND last_tested_at IS NOT NULL AND error_code IS NOT NULL) OR (status = 'disabled' AND error_code IS NULL AND (verified_at IS NULL OR (last_tested_at IS NOT NULL AND verified_at = last_tested_at)))),
	FOREIGN KEY(supersedes_id) REFERENCES analysis_model_config (id) ON DELETE RESTRICT,
	CONSTRAINT uq_analysis_model_config_supersedes UNIQUE (supersedes_id)
);
CREATE TABLE analysis_report (
	run_id VARCHAR(36) NOT NULL,
	report_id VARCHAR(71) NOT NULL,
	report_json TEXT NOT NULL,
	report_hash VARCHAR(71) NOT NULL,
	created_at DATETIME NOT NULL,
	PRIMARY KEY (run_id),
	CONSTRAINT ck_analysis_report_id CHECK (length(report_id) = 71 AND substr(report_id, 1, 7) = 'sha256:'),
	CONSTRAINT ck_analysis_report_hash CHECK (length(report_hash) = 71 AND substr(report_hash, 1, 7) = 'sha256:'),
	CONSTRAINT ck_analysis_report_json CHECK (json_valid(report_json) = 1 AND json_type(report_json) = 'object' AND length(CAST(report_json AS BLOB)) <= 1048576),
	FOREIGN KEY(run_id) REFERENCES analysis_run (id) ON DELETE CASCADE
);
CREATE TABLE analysis_run (
	id VARCHAR(36) NOT NULL,
	task_id VARCHAR(36) NOT NULL,
	parent_run_id VARCHAR(36),
	requested_stage VARCHAR(32),
	symbol VARCHAR(9) NOT NULL,
	model_config_id VARCHAR(71) NOT NULL,
	model_provider VARCHAR(64) NOT NULL,
	model_name VARCHAR(256) NOT NULL,
	model_config_json TEXT NOT NULL,
	model_config_hash VARCHAR(71) NOT NULL,
	status VARCHAR(32) NOT NULL,
	current_stage VARCHAR(32),
	error_json TEXT,
	config_fingerprint VARCHAR(71) NOT NULL,
	snapshot_id VARCHAR(71),
	snapshot_json TEXT,
	snapshot_hash VARCHAR(71),
	evidence_graph_json TEXT,
	evidence_graph_hash VARCHAR(71),
	retry_policy_json TEXT NOT NULL,
	retry_policy_hash VARCHAR(71) NOT NULL,
	created_at DATETIME NOT NULL,
	updated_at DATETIME NOT NULL,
	started_at DATETIME,
	finished_at DATETIME,
	PRIMARY KEY (id),
	CONSTRAINT ck_analysis_run_symbol CHECK (symbol GLOB '[0-9][0-9][0-9][0-9][0-9][0-9].SH' OR symbol GLOB '[0-9][0-9][0-9][0-9][0-9][0-9].SZ' OR symbol GLOB '[0-9][0-9][0-9][0-9][0-9][0-9].BJ'),
	CONSTRAINT ck_analysis_run_status CHECK (status IN ('queued','running','succeeded','partial','insufficient_evidence','failed','cancelled')),
	CONSTRAINT ck_analysis_run_requested_stage CHECK (requested_stage IS NULL OR requested_stage IN ('technical','fundamental_news','bull','bear','risk_decision')),
	CONSTRAINT ck_analysis_run_current_stage CHECK (current_stage IS NULL OR current_stage IN ('market','fundamentals','announcements','news','technical','fundamental_news','bull','bear','risk_decision')),
	CONSTRAINT ck_analysis_run_input_binding CHECK ((snapshot_id IS NULL AND snapshot_json IS NULL AND snapshot_hash IS NULL AND evidence_graph_json IS NULL AND evidence_graph_hash IS NULL) OR (snapshot_id IS NOT NULL AND snapshot_json IS NOT NULL AND snapshot_hash IS NOT NULL AND evidence_graph_json IS NOT NULL AND evidence_graph_hash IS NOT NULL)),
	CONSTRAINT ck_analysis_run_snapshot_id CHECK (snapshot_id IS NULL OR (length(snapshot_id) = 71 AND substr(snapshot_id, 1, 7) = 'sha256:')),
	CONSTRAINT ck_analysis_run_snapshot_hash CHECK (snapshot_hash IS NULL OR (length(snapshot_hash) = 71 AND substr(snapshot_hash, 1, 7) = 'sha256:')),
	CONSTRAINT ck_analysis_run_evidence_hash CHECK (evidence_graph_hash IS NULL OR (length(evidence_graph_hash) = 71 AND substr(evidence_graph_hash, 1, 7) = 'sha256:')),
	CONSTRAINT ck_analysis_run_retry_hash CHECK (length(retry_policy_hash) = 71 AND substr(retry_policy_hash, 1, 7) = 'sha256:'),
	CONSTRAINT ck_analysis_run_snapshot_json CHECK (snapshot_json IS NULL OR (json_valid(snapshot_json) = 1 AND json_type(snapshot_json) = 'object' AND length(CAST(snapshot_json AS BLOB)) <= 2097152)),
	CONSTRAINT ck_analysis_run_evidence_json CHECK (evidence_graph_json IS NULL OR (json_valid(evidence_graph_json) = 1 AND json_type(evidence_graph_json) = 'object' AND length(CAST(evidence_graph_json AS BLOB)) <= 4194304)),
	CONSTRAINT ck_analysis_run_retry_json CHECK (json_valid(retry_policy_json) = 1 AND json_type(retry_policy_json) = 'object' AND length(CAST(retry_policy_json AS BLOB)) <= 16384),
	CONSTRAINT ck_analysis_run_error_json CHECK (error_json IS NULL OR (json_valid(error_json) = 1 AND json_type(error_json) = 'object' AND length(CAST(error_json AS BLOB)) <= 16384)),
	CONSTRAINT ck_analysis_run_config_fingerprint CHECK (length(config_fingerprint) = 71 AND substr(config_fingerprint, 1, 7) = 'sha256:'),
	CONSTRAINT ck_analysis_run_model_config_id CHECK (length(model_config_id) = 71 AND substr(model_config_id, 1, 7) = 'sha256:'),
	CONSTRAINT ck_analysis_run_model_provider CHECK (length(model_provider) BETWEEN 1 AND 64),
	CONSTRAINT ck_analysis_run_model_name CHECK (length(model_name) BETWEEN 1 AND 256),
	CONSTRAINT ck_analysis_run_model_config_json CHECK (json_valid(model_config_json) = 1 AND json_type(model_config_json) = 'object' AND length(CAST(model_config_json AS BLOB)) <= 16384),
	CONSTRAINT ck_analysis_run_model_config_hash CHECK (length(model_config_hash) = 71 AND substr(model_config_hash, 1, 7) = 'sha256:'),
	CONSTRAINT ck_analysis_run_state_shape CHECK ((status = 'queued' AND started_at IS NULL AND finished_at IS NULL AND error_json IS NULL) OR (status = 'running' AND started_at IS NOT NULL AND finished_at IS NULL AND error_json IS NULL) OR (status IN ('succeeded','partial','insufficient_evidence') AND started_at IS NOT NULL AND finished_at IS NOT NULL AND current_stage IS NULL AND error_json IS NULL) OR (status = 'failed' AND started_at IS NOT NULL AND finished_at IS NOT NULL AND current_stage IS NULL AND error_json IS NOT NULL) OR (status = 'cancelled' AND finished_at IS NOT NULL AND current_stage IS NULL)),
	FOREIGN KEY(task_id) REFERENCES task_run (id) ON DELETE RESTRICT,
	FOREIGN KEY(parent_run_id) REFERENCES analysis_run (id) ON DELETE RESTRICT,
	CONSTRAINT uq_analysis_run_task UNIQUE (task_id)
);
CREATE TABLE analysis_stage (
	run_id VARCHAR(36) NOT NULL,
	role VARCHAR(32) NOT NULL,
	ordinal INTEGER NOT NULL,
	status VARCHAR(16) NOT NULL,
	source_run_id VARCHAR(36),
	source_role VARCHAR(32),
	output_json TEXT,
	output_hash VARCHAR(71),
	trace_json TEXT,
	trace_hash VARCHAR(71),
	failure_code VARCHAR(64),
	retryable BOOLEAN,
	attempt_count INTEGER DEFAULT '0' NOT NULL,
	created_at DATETIME NOT NULL,
	updated_at DATETIME NOT NULL,
	started_at DATETIME,
	finished_at DATETIME,
	PRIMARY KEY (run_id, role),
	CONSTRAINT ck_analysis_stage_role_ordinal CHECK ((role = 'market' AND ordinal = -4) OR (role = 'fundamentals' AND ordinal = -3) OR (role = 'announcements' AND ordinal = -2) OR (role = 'news' AND ordinal = -1) OR (role = 'technical' AND ordinal = 0) OR (role = 'fundamental_news' AND ordinal = 1) OR (role = 'bull' AND ordinal = 2) OR (role = 'bear' AND ordinal = 3) OR (role = 'risk_decision' AND ordinal = 4)),
	CONSTRAINT ck_analysis_stage_status CHECK (status IN ('pending','running','succeeded','failed','blocked','reused','cancelled')),
	CONSTRAINT ck_analysis_stage_source CHECK ((source_run_id IS NULL AND source_role IS NULL) OR (source_run_id IS NOT NULL AND source_role = role AND source_run_id <> run_id)),
	CONSTRAINT ck_analysis_stage_attempt_count CHECK (attempt_count >= 0),
	CONSTRAINT ck_analysis_stage_failure_code CHECK (failure_code IS NULL OR (length(failure_code) BETWEEN 1 AND 64 AND failure_code NOT GLOB '*[^a-z0-9_]*')),
	CONSTRAINT ck_analysis_stage_state_shape CHECK ((status = 'pending' AND source_run_id IS NULL AND output_json IS NULL AND output_hash IS NULL AND trace_json IS NULL AND trace_hash IS NULL AND failure_code IS NULL AND retryable IS NULL AND finished_at IS NULL) OR (status = 'running' AND source_run_id IS NULL AND output_json IS NULL AND output_hash IS NULL AND trace_json IS NULL AND trace_hash IS NULL AND failure_code IS NULL AND retryable IS NULL AND started_at IS NOT NULL AND finished_at IS NULL AND attempt_count >= 1) OR (status = 'succeeded' AND source_run_id IS NULL AND output_json IS NOT NULL AND output_hash IS NOT NULL AND trace_json IS NOT NULL AND trace_hash IS NOT NULL AND failure_code IS NULL AND retryable IS NULL AND started_at IS NOT NULL AND finished_at IS NOT NULL) OR (status = 'reused' AND source_run_id IS NOT NULL AND output_json IS NULL AND output_hash IS NULL AND trace_json IS NULL AND trace_hash IS NULL AND failure_code IS NULL AND retryable IS NULL AND attempt_count = 0 AND finished_at IS NOT NULL) OR (status = 'failed' AND source_run_id IS NULL AND trace_json IS NULL AND trace_hash IS NULL AND failure_code IS NOT NULL AND retryable IS NOT NULL AND attempt_count >= 1 AND (((role IN ('market','fundamentals','announcements','news')) AND output_json IS NOT NULL AND output_hash IS NOT NULL) OR ((role NOT IN ('market','fundamentals','announcements','news')) AND output_json IS NULL AND output_hash IS NULL)) AND finished_at IS NOT NULL) OR (status = 'blocked' AND source_run_id IS NULL AND output_json IS NULL AND output_hash IS NULL AND trace_json IS NULL AND trace_hash IS NULL AND failure_code IS NOT NULL AND retryable = 0 AND finished_at IS NOT NULL) OR (status = 'cancelled' AND source_run_id IS NULL AND output_json IS NULL AND output_hash IS NULL AND trace_json IS NULL AND trace_hash IS NULL AND failure_code IS NULL AND retryable IS NULL AND finished_at IS NOT NULL)),
	CONSTRAINT ck_analysis_stage_output_json CHECK (output_json IS NULL OR json_valid(output_json) = 1 AND json_type(output_json) = 'object' AND length(CAST(output_json AS BLOB)) <= 65536),
	CONSTRAINT ck_analysis_stage_trace_json CHECK (trace_json IS NULL OR json_valid(trace_json) = 1 AND json_type(trace_json) = 'object' AND length(CAST(trace_json AS BLOB)) <= 32768),
	CONSTRAINT ck_analysis_stage_output_hash CHECK (output_hash IS NULL OR (length(output_hash) = 71 AND substr(output_hash, 1, 7) = 'sha256:')),
	CONSTRAINT ck_analysis_stage_trace_hash CHECK (trace_hash IS NULL OR (length(trace_hash) = 71 AND substr(trace_hash, 1, 7) = 'sha256:')),
	FOREIGN KEY(run_id) REFERENCES analysis_run (id) ON DELETE CASCADE,
	FOREIGN KEY(source_run_id, source_role) REFERENCES analysis_stage (run_id, role) ON DELETE RESTRICT,
	CONSTRAINT uq_analysis_stage_ordinal UNIQUE (run_id, ordinal)
);
CREATE TABLE app_setting (
	"key" VARCHAR(255) NOT NULL,
	encrypted_value TEXT NOT NULL,
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY ("key")
);
CREATE TABLE backtest_aggregate_metric (
	run_id VARCHAR(36) NOT NULL,
	metric_key VARCHAR(64) NOT NULL,
	payload_json JSON NOT NULL,
	PRIMARY KEY (run_id, metric_key),
	FOREIGN KEY(run_id) REFERENCES backtest_run (id) ON DELETE CASCADE
);
CREATE TABLE backtest_failure (
	run_id VARCHAR(36) NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	ordinal INTEGER NOT NULL,
	reason VARCHAR(64) NOT NULL,
	detail_json JSON NOT NULL,
	PRIMARY KEY (run_id, symbol, ordinal),
	CONSTRAINT ck_backtest_failure_ordinal CHECK (ordinal >= 0),
	FOREIGN KEY(run_id, symbol) REFERENCES backtest_symbol (run_id, symbol) ON DELETE CASCADE
);
CREATE TABLE backtest_group_metric (
	run_id VARCHAR(36) NOT NULL,
	dimension VARCHAR(32) NOT NULL,
	group_key TEXT NOT NULL,
	payload_json JSON NOT NULL,
	PRIMARY KEY (run_id, dimension, group_key),
	CONSTRAINT ck_backtest_group_dimension CHECK (dimension IN ('symbol','entry_month','entry_year')),
	FOREIGN KEY(run_id) REFERENCES backtest_run (id) ON DELETE CASCADE
);
CREATE TABLE backtest_log (
	run_id VARCHAR(36) NOT NULL,
	ordinal INTEGER NOT NULL,
	level VARCHAR(16) NOT NULL,
	message VARCHAR(128) NOT NULL,
	detail_json JSON NOT NULL,
	PRIMARY KEY (run_id, ordinal),
	CONSTRAINT ck_backtest_log_ordinal CHECK (ordinal >= 0),
	CONSTRAINT ck_backtest_log_level CHECK (level IN ('info','warning','error')),
	FOREIGN KEY(run_id) REFERENCES backtest_run (id) ON DELETE CASCADE
);
CREATE TABLE backtest_order_event (
	run_id VARCHAR(36) NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	ordinal INTEGER NOT NULL,
	event_type VARCHAR(32) NOT NULL,
	payload_json JSON NOT NULL,
	PRIMARY KEY (run_id, symbol, ordinal),
	CONSTRAINT ck_backtest_order_event_ordinal CHECK (ordinal >= 0),
	FOREIGN KEY(run_id, symbol) REFERENCES backtest_symbol (run_id, symbol) ON DELETE CASCADE
);
CREATE TABLE backtest_run (
	id VARCHAR(36) NOT NULL,
	task_id VARCHAR(36) NOT NULL,
	snapshot_id VARCHAR(71) NOT NULL,
	snapshot_json JSON NOT NULL,
	status VARCHAR(32) NOT NULL,
	stage VARCHAR(32) NOT NULL,
	total INTEGER NOT NULL,
	processed INTEGER NOT NULL,
	failed_count INTEGER NOT NULL,
	result_hash VARCHAR(71),
	actual_warmup_start DATETIME,
	created_at DATETIME NOT NULL,
	updated_at DATETIME NOT NULL,
	started_at DATETIME,
	finished_at DATETIME,
	PRIMARY KEY (id),
	CONSTRAINT ck_backtest_run_status CHECK (status IN ('queued','running','succeeded','partial_failed','failed','cancelled')),
	CONSTRAINT ck_backtest_run_stage CHECK (stage IN ('queued','executing','completed','failed','cancelled')),
	CONSTRAINT ck_backtest_run_total CHECK (total BETWEEN 1 AND 10000),
	CONSTRAINT ck_backtest_run_counts CHECK (failed_count >= 0 AND failed_count <= processed AND processed <= total),
	FOREIGN KEY(task_id) REFERENCES task_run (id) ON DELETE RESTRICT,
	CONSTRAINT uq_backtest_run_task UNIQUE (task_id)
);
CREATE TABLE backtest_symbol (
	run_id VARCHAR(36) NOT NULL,
	ordinal INTEGER NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	input_kind VARCHAR(16) NOT NULL,
	reference_json JSON NOT NULL,
	status VARCHAR(16) NOT NULL,
	signal_series_id VARCHAR(71),
	warmup_start DATETIME,
	failure_reason VARCHAR(64),
	created_at DATETIME NOT NULL,
	updated_at DATETIME NOT NULL,
	PRIMARY KEY (run_id, ordinal),
	CONSTRAINT ck_backtest_symbol_ordinal CHECK (ordinal BETWEEN 0 AND 9999),
	CONSTRAINT ck_backtest_symbol_input_kind CHECK (input_kind IN ('runnable','gap')),
	CONSTRAINT ck_backtest_symbol_status CHECK (status IN ('pending','succeeded','failed')),
	FOREIGN KEY(run_id) REFERENCES backtest_run (id) ON DELETE CASCADE,
	CONSTRAINT uq_backtest_symbol_owner UNIQUE (run_id, symbol)
);
CREATE TABLE backtest_trade (
	run_id VARCHAR(36) NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	ordinal INTEGER NOT NULL,
	realized BOOLEAN NOT NULL,
	payload_json JSON NOT NULL,
	PRIMARY KEY (run_id, symbol, ordinal),
	FOREIGN KEY(run_id, symbol) REFERENCES backtest_symbol (run_id, symbol) ON DELETE CASCADE,
	CONSTRAINT ck_backtest_trade_ordinal CHECK (ordinal >= 0)
);
CREATE TABLE custom_pool (
	pool_id VARCHAR(36) NOT NULL,
	name VARCHAR(64) NOT NULL,
	revision INTEGER NOT NULL,
	instrument_manifest_record_id VARCHAR(71) NOT NULL,
	instrument_dataset_version VARCHAR(71) NOT NULL,
	member_count INTEGER NOT NULL,
	member_digest VARCHAR(71) NOT NULL,
	state_digest VARCHAR(71) NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (pool_id),
	CONSTRAINT ck_custom_pool_name CHECK (length(name) BETWEEN 1 AND 64 AND trim(name) = name),
	CONSTRAINT ck_custom_pool_revision CHECK (revision > 0),
	CONSTRAINT ck_custom_pool_member_count CHECK (member_count BETWEEN 1 AND 5000),
	CONSTRAINT ck_custom_pool_member_digest CHECK (length(member_digest) = 71 AND substr(member_digest, 1, 7) = 'sha256:'),
	CONSTRAINT ck_custom_pool_state_digest CHECK (length(state_digest) = 71 AND substr(state_digest, 1, 7) = 'sha256:'),
	FOREIGN KEY(instrument_manifest_record_id, instrument_dataset_version) REFERENCES instrument_routing_manifest (manifest_record_id, dataset_version) ON DELETE RESTRICT,
	CONSTRAINT uq_custom_pool_revision_dataset UNIQUE (pool_id, revision, instrument_dataset_version)
);
CREATE TABLE custom_pool_member (
	pool_id VARCHAR(36) NOT NULL,
	ordinal INTEGER NOT NULL,
	member_revision INTEGER NOT NULL,
	instrument_dataset_version VARCHAR(71) NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	PRIMARY KEY (pool_id, ordinal),
	CONSTRAINT ck_custom_pool_member_ordinal CHECK (ordinal BETWEEN 0 AND 4999),
	CONSTRAINT ck_custom_pool_member_revision CHECK (member_revision > 0),
	FOREIGN KEY(pool_id, member_revision, instrument_dataset_version) REFERENCES custom_pool (pool_id, revision, instrument_dataset_version) ON DELETE CASCADE,
	FOREIGN KEY(instrument_dataset_version, symbol) REFERENCES instrument_dataset_item (dataset_version, symbol) ON DELETE RESTRICT,
	CONSTRAINT uq_custom_pool_member_symbol UNIQUE (pool_id, symbol)
);
CREATE TABLE execution_status_dataset (
	dataset_version VARCHAR(71) NOT NULL,
	source VARCHAR(32) NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	exchange VARCHAR(2) NOT NULL,
	period VARCHAR(8) NOT NULL,
	query_start DATE NOT NULL,
	query_end DATE NOT NULL,
	fetched_at DATETIME NOT NULL,
	data_cutoff DATETIME NOT NULL,
	row_count BIGINT NOT NULL,
	snapshot_json JSON NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (dataset_version),
	CONSTRAINT ck_execution_status_dataset_row_count_positive CHECK (row_count > 0),
	CONSTRAINT ck_execution_status_dataset_period CHECK (period IN ('1d', '1w', '60m'))
)
 WITHOUT ROWID

;
CREATE TABLE execution_status_routing_manifest (
	manifest_record_id VARCHAR(71) NOT NULL,
	dataset_version VARCHAR(71) NOT NULL,
	route_version VARCHAR(71) NOT NULL,
	manifest_json JSON NOT NULL,
	fetched_at DATETIME NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (manifest_record_id),
	FOREIGN KEY(dataset_version) REFERENCES execution_status_dataset (dataset_version) ON DELETE RESTRICT
)
 WITHOUT ROWID

;
CREATE TABLE formula (
	id VARCHAR(36) NOT NULL,
	name VARCHAR(64) NOT NULL,
	formula_type VARCHAR(16) NOT NULL,
	placement VARCHAR(16) NOT NULL,
	latest_version INTEGER NOT NULL,
	created_at DATETIME NOT NULL,
	updated_at DATETIME NOT NULL,
	PRIMARY KEY (id),
	CONSTRAINT ck_formula_type CHECK (formula_type IN ('indicator','trading')),
	CONSTRAINT ck_formula_placement CHECK (placement IN ('main','subchart')),
	CONSTRAINT ck_formula_name CHECK (length(name) BETWEEN 1 AND 64 AND trim(name) = name),
	CONSTRAINT ck_formula_latest_version CHECK (latest_version >= 0)
);
CREATE TABLE formula_draft (
	formula_id VARCHAR(36) NOT NULL,
	revision INTEGER NOT NULL,
	source TEXT NOT NULL,
	source_checksum VARCHAR(71) NOT NULL,
	parameter_schema_json JSON NOT NULL,
	validation_result_json JSON NOT NULL,
	executable_version_id VARCHAR(36),
	updated_at DATETIME NOT NULL,
	PRIMARY KEY (formula_id),
	CONSTRAINT ck_formula_draft_source CHECK (length(CAST(source AS BLOB)) BETWEEN 1 AND 64000),
	CONSTRAINT ck_formula_draft_checksum CHECK (length(source_checksum) = 71 AND source_checksum LIKE 'sha256:%'),
	CONSTRAINT ck_formula_draft_revision CHECK (revision > 0),
	FOREIGN KEY(formula_id) REFERENCES formula (id) ON DELETE CASCADE,
	FOREIGN KEY(formula_id, executable_version_id) REFERENCES formula_version (formula_id, id) ON DELETE RESTRICT
);
CREATE TABLE formula_version (
	id VARCHAR(36) NOT NULL,
	formula_id VARCHAR(36) NOT NULL,
	version INTEGER NOT NULL,
	name VARCHAR(64) NOT NULL,
	formula_type VARCHAR(16) NOT NULL,
	placement VARCHAR(16) NOT NULL,
	source TEXT NOT NULL,
	parameter_schema_json JSON NOT NULL,
	compatibility_version VARCHAR(32) NOT NULL,
	engine_version VARCHAR(32) NOT NULL,
	checksum VARCHAR(71) NOT NULL,
	validation_result_json JSON NOT NULL,
	copied_from_version_id VARCHAR(36),
	created_at DATETIME NOT NULL,
	PRIMARY KEY (id),
	CONSTRAINT ck_formula_version_positive CHECK (version > 0),
	CONSTRAINT ck_formula_version_type CHECK (formula_type IN ('indicator','trading')),
	CONSTRAINT ck_formula_version_placement CHECK (placement IN ('main','subchart')),
	CONSTRAINT ck_formula_version_source CHECK (length(CAST(source AS BLOB)) BETWEEN 1 AND 64000),
	CONSTRAINT ck_formula_version_name CHECK (length(name) BETWEEN 1 AND 64 AND trim(name) = name),
	CONSTRAINT ck_formula_version_checksum CHECK (length(checksum) = 71 AND checksum LIKE 'sha256:%'),
	FOREIGN KEY(copied_from_version_id) REFERENCES formula_version (id) ON DELETE RESTRICT,
	FOREIGN KEY(formula_id) REFERENCES formula (id) ON DELETE RESTRICT,
	CONSTRAINT uq_formula_version_number UNIQUE (formula_id, version),
	CONSTRAINT uq_formula_version_owner_identity UNIQUE (formula_id, id)
);
CREATE TABLE instrument_dataset (
	dataset_version VARCHAR(71) NOT NULL,
	source VARCHAR(32) NOT NULL,
	data_cutoff DATETIME NOT NULL,
	row_count INTEGER NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (dataset_version),
	CONSTRAINT ck_instrument_dataset_row_count_bounded CHECK (row_count BETWEEN 1 AND 50000)
)
 WITHOUT ROWID

;
CREATE TABLE instrument_dataset_item (
	dataset_version VARCHAR(71) NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	ordinal INTEGER NOT NULL,
	exchange VARCHAR(2) NOT NULL,
	name VARCHAR(255) NOT NULL,
	instrument_kind VARCHAR(16) NOT NULL,
	listing_status VARCHAR(16) NOT NULL,
	listed_on DATE,
	delisted_on DATE,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (dataset_version, symbol),
	CONSTRAINT ck_instrument_dataset_item_ordinal CHECK (ordinal BETWEEN 0 AND 49999),
	CONSTRAINT ck_instrument_dataset_item_name_length CHECK (length(name) BETWEEN 1 AND 255),
	FOREIGN KEY(dataset_version) REFERENCES instrument_dataset (dataset_version) ON DELETE RESTRICT,
	CONSTRAINT uq_instrument_dataset_item_ordinal UNIQUE (dataset_version, ordinal)
)
 WITHOUT ROWID

;
CREATE TABLE instrument_routing_manifest (
	manifest_record_id VARCHAR(71) NOT NULL,
	dataset_version VARCHAR(71) NOT NULL,
	route_version VARCHAR(71) NOT NULL,
	manifest_json JSON NOT NULL,
	fetched_at DATETIME NOT NULL,
	data_cutoff DATETIME NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (manifest_record_id),
	FOREIGN KEY(dataset_version) REFERENCES instrument_dataset (dataset_version) ON DELETE RESTRICT,
	CONSTRAINT uq_instrument_routing_manifest_dataset UNIQUE (manifest_record_id, dataset_version)
)
 WITHOUT ROWID

;
CREATE TABLE market_dataset (
	dataset_version VARCHAR(71) NOT NULL,
	source VARCHAR(32) NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	period VARCHAR(8) NOT NULL,
	adjustment VARCHAR(8) NOT NULL,
	query_start DATETIME NOT NULL,
	query_end DATETIME NOT NULL,
	data_cutoff DATETIME NOT NULL,
	row_count BIGINT NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (dataset_version),
	CONSTRAINT ck_market_dataset_row_count_positive CHECK (row_count > 0),
	CONSTRAINT uq_market_dataset_version_symbol UNIQUE (dataset_version, symbol)
)
 WITHOUT ROWID

;
CREATE TABLE market_dataset_partition (
	dataset_version VARCHAR(71) NOT NULL,
	partition_manifest_id VARCHAR(71) NOT NULL,
	partition_year INTEGER NOT NULL,
	relative_path TEXT NOT NULL,
	row_count BIGINT NOT NULL,
	byte_size BIGINT NOT NULL,
	physical_sha256 VARCHAR(71) NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (dataset_version, partition_manifest_id),
	CONSTRAINT ck_market_dataset_partition_byte_size_positive CHECK (byte_size > 0),
	CONSTRAINT ck_market_dataset_partition_row_count_positive CHECK (row_count > 0),
	CONSTRAINT ck_market_dataset_partition_year CHECK (partition_year BETWEEN 1900 AND 9999),
	FOREIGN KEY(dataset_version) REFERENCES market_dataset (dataset_version) ON DELETE RESTRICT,
	CONSTRAINT uq_market_dataset_partition_dataset_year UNIQUE (dataset_version, partition_year),
	CONSTRAINT uq_market_dataset_partition_relative_path UNIQUE (relative_path)
)
 WITHOUT ROWID

;
CREATE TABLE market_dataset_timestamp (
	dataset_version VARCHAR(71) NOT NULL,
	ordinal INTEGER NOT NULL,
	timestamp DATETIME NOT NULL,
	PRIMARY KEY (dataset_version, ordinal),
	CONSTRAINT ck_market_dataset_timestamp_ordinal CHECK (ordinal >= 0),
	FOREIGN KEY(dataset_version) REFERENCES market_dataset (dataset_version) ON DELETE CASCADE,
	CONSTRAINT uq_market_dataset_timestamp_value UNIQUE (dataset_version, timestamp)
)
 WITHOUT ROWID

;
CREATE TABLE market_dataset_timestamp_seal (
	dataset_version VARCHAR(71) NOT NULL,
	index_version VARCHAR(32) NOT NULL,
	row_count BIGINT NOT NULL,
	timestamp_digest VARCHAR(71) NOT NULL,
	PRIMARY KEY (dataset_version),
	CONSTRAINT ck_market_dataset_timestamp_seal_row_count CHECK (row_count > 0),
	FOREIGN KEY(dataset_version) REFERENCES market_dataset (dataset_version) ON DELETE CASCADE
)
 WITHOUT ROWID

;
CREATE TABLE market_routing_manifest (
	manifest_record_id VARCHAR(71) NOT NULL,
	dataset_version VARCHAR(71) NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	route_version VARCHAR(71) NOT NULL,
	manifest_json JSON NOT NULL,
	fetched_at DATETIME NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (manifest_record_id),
	FOREIGN KEY(dataset_version, symbol) REFERENCES market_dataset (dataset_version, symbol) ON DELETE RESTRICT,
	CONSTRAINT uq_market_routing_manifest_provenance UNIQUE (manifest_record_id, dataset_version, symbol)
)
 WITHOUT ROWID

;
CREATE TABLE market_update_item (
	task_id VARCHAR(36) NOT NULL,
	ordinal INTEGER NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	status VARCHAR(16) NOT NULL,
	manifest_record_id VARCHAR(71),
	dataset_version VARCHAR(71),
	reason VARCHAR(512),
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (task_id, ordinal),
	CONSTRAINT ck_market_update_item_ordinal CHECK (ordinal >= 0),
	CONSTRAINT ck_market_update_item_outcome CHECK ((status = 'succeeded' AND manifest_record_id IS NOT NULL AND dataset_version IS NOT NULL AND reason IS NULL) OR (status IN ('failed', 'cancelled') AND manifest_record_id IS NULL AND dataset_version IS NULL AND reason IS NOT NULL)),
	CONSTRAINT ck_market_update_item_status CHECK (status IN ('succeeded', 'failed', 'cancelled')),
	FOREIGN KEY(dataset_version) REFERENCES market_dataset (dataset_version) ON DELETE RESTRICT,
	FOREIGN KEY(manifest_record_id, dataset_version, symbol) REFERENCES market_routing_manifest (manifest_record_id, dataset_version, symbol) ON DELETE RESTRICT,
	FOREIGN KEY(task_id) REFERENCES task_run (id) ON DELETE RESTRICT,
	CONSTRAINT uq_market_update_item_task_symbol UNIQUE (task_id, symbol)
)
 WITHOUT ROWID

;
CREATE TABLE market_update_occurrence (
	schedule_id VARCHAR(36) NOT NULL,
	local_date DATE NOT NULL,
	task_id VARCHAR(36) NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (schedule_id, local_date),
	FOREIGN KEY(schedule_id) REFERENCES market_update_schedule (id) ON DELETE RESTRICT,
	FOREIGN KEY(task_id) REFERENCES task_run (id) DEFERRABLE INITIALLY DEFERRED,
	CONSTRAINT uq_market_update_occurrence_task_id UNIQUE (task_id)
)
 WITHOUT ROWID

;
CREATE TABLE market_update_schedule (
	id VARCHAR(36) NOT NULL,
	enabled BOOLEAN DEFAULT 1 NOT NULL,
	timezone VARCHAR(64) DEFAULT 'Asia/Shanghai' NOT NULL,
	local_time TIME NOT NULL,
	payload_json JSON DEFAULT '{}' NOT NULL,
	last_enqueued_local_date DATE,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (id),
	CONSTRAINT ck_market_update_schedule_timezone CHECK (timezone = 'Asia/Shanghai')
);
CREATE TABLE preset_pool_member (
	snapshot_id VARCHAR(71) NOT NULL,
	ordinal INTEGER NOT NULL,
	instrument_dataset_version VARCHAR(71) NOT NULL,
	symbol VARCHAR(9) NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (snapshot_id, ordinal),
	CONSTRAINT ck_preset_pool_member_ordinal CHECK (ordinal BETWEEN 0 AND 9999),
	FOREIGN KEY(snapshot_id, instrument_dataset_version) REFERENCES preset_pool_snapshot (snapshot_id, instrument_dataset_version) ON DELETE RESTRICT,
	FOREIGN KEY(instrument_dataset_version, symbol) REFERENCES instrument_dataset_item (dataset_version, symbol) ON DELETE RESTRICT,
	CONSTRAINT uq_preset_pool_member_symbol UNIQUE (snapshot_id, symbol)
)
 WITHOUT ROWID

;
CREATE TABLE preset_pool_snapshot (
	snapshot_id VARCHAR(71) NOT NULL,
	pool_id VARCHAR(71) NOT NULL,
	preset_key VARCHAR(64) NOT NULL,
	category VARCHAR(16) NOT NULL,
	display_name VARCHAR(64) NOT NULL,
	source VARCHAR(32) NOT NULL,
	composition_dataset_version VARCHAR(71) NOT NULL,
	composition_route_version VARCHAR(71) NOT NULL,
	fetched_at DATETIME NOT NULL,
	data_cutoff DATETIME NOT NULL,
	complete BOOLEAN NOT NULL,
	instrument_manifest_record_id VARCHAR(71) NOT NULL,
	instrument_dataset_version VARCHAR(71) NOT NULL,
	member_count INTEGER NOT NULL,
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (snapshot_id),
	CONSTRAINT ck_preset_pool_snapshot_logical_id CHECK (pool_id = 'preset:' || preset_key),
	CONSTRAINT ck_preset_pool_snapshot_category CHECK (category IN ('all_a', 'index', 'industry')),
	CONSTRAINT ck_preset_pool_snapshot_complete CHECK (complete = 1),
	CONSTRAINT ck_preset_pool_snapshot_member_count CHECK (member_count BETWEEN 1 AND 10000),
	FOREIGN KEY(instrument_manifest_record_id, instrument_dataset_version) REFERENCES instrument_routing_manifest (manifest_record_id, dataset_version) ON DELETE RESTRICT,
	CONSTRAINT uq_preset_pool_snapshot_dataset UNIQUE (snapshot_id, instrument_dataset_version)
)
 WITHOUT ROWID

;
CREATE TABLE task_event (
	id VARCHAR(36) NOT NULL,
	task_id VARCHAR(36) NOT NULL,
	event_name VARCHAR(64) NOT NULL,
	level VARCHAR(16) NOT NULL,
	progress FLOAT,
	detail_json JSON DEFAULT '{}' NOT NULL,
	occurred_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL,
	PRIMARY KEY (id),
	FOREIGN KEY(task_id) REFERENCES task_run (id) ON DELETE CASCADE
);
