CREATE INDEX ix_task_run_status_created_at ON task_run (status, created_at);
CREATE INDEX ix_task_event_task_id_occurred_at ON task_event (task_id, occurred_at);
CREATE INDEX ix_market_dataset_exact_query ON market_dataset (symbol, period, adjustment, query_start, query_end);
CREATE INDEX ix_market_routing_manifest_dataset_fetched_at ON market_routing_manifest (dataset_version, fetched_at);
CREATE INDEX ix_market_routing_manifest_route_version ON market_routing_manifest (route_version);
CREATE INDEX ix_market_update_schedule_due ON market_update_schedule (enabled, local_time, last_enqueued_local_date);
CREATE TRIGGER trg_market_update_item_owner_running
            BEFORE INSERT ON market_update_item
            WHEN NOT EXISTS (
                SELECT 1
                FROM task_run
                WHERE id = NEW.task_id
                  AND kind = 'market.update'
                  AND status = 'running'
            )
            BEGIN
                SELECT RAISE(
                    ABORT,
                    'market_update_item requires running market update task'
                );
            END;
CREATE TRIGGER trg_market_dataset_immutable_insert
            BEFORE INSERT ON market_dataset
            WHEN EXISTS (
                SELECT 1
                FROM market_dataset
                WHERE dataset_version = NEW.dataset_version
            )
            BEGIN
                SELECT RAISE(ABORT, 'market_dataset rows are immutable');
            END;
CREATE TRIGGER trg_market_dataset_immutable_update
                BEFORE UPDATE ON market_dataset
                BEGIN
                    SELECT RAISE(ABORT, 'market_dataset rows are immutable');
                END;
CREATE TRIGGER trg_market_dataset_immutable_delete
                BEFORE DELETE ON market_dataset
                BEGIN
                    SELECT RAISE(ABORT, 'market_dataset rows are immutable');
                END;
CREATE TRIGGER trg_market_dataset_partition_immutable_insert
            BEFORE INSERT ON market_dataset_partition
            WHEN EXISTS (
                SELECT 1
                FROM market_dataset_partition
                WHERE
        (dataset_version = NEW.dataset_version
         AND partition_manifest_id = NEW.partition_manifest_id)
        OR (dataset_version = NEW.dataset_version
            AND partition_year = NEW.partition_year)
        OR relative_path = NEW.relative_path

            )
            BEGIN
                SELECT RAISE(ABORT, 'market_dataset_partition rows are immutable');
            END;
CREATE TRIGGER trg_market_dataset_partition_immutable_update
                BEFORE UPDATE ON market_dataset_partition
                BEGIN
                    SELECT RAISE(ABORT, 'market_dataset_partition rows are immutable');
                END;
CREATE TRIGGER trg_market_dataset_partition_immutable_delete
                BEFORE DELETE ON market_dataset_partition
                BEGIN
                    SELECT RAISE(ABORT, 'market_dataset_partition rows are immutable');
                END;
CREATE TRIGGER trg_market_routing_manifest_immutable_insert
            BEFORE INSERT ON market_routing_manifest
            WHEN EXISTS (
                SELECT 1
                FROM market_routing_manifest
                WHERE manifest_record_id = NEW.manifest_record_id
            )
            BEGIN
                SELECT RAISE(ABORT, 'market_routing_manifest rows are immutable');
            END;
CREATE TRIGGER trg_market_routing_manifest_immutable_update
                BEFORE UPDATE ON market_routing_manifest
                BEGIN
                    SELECT RAISE(ABORT, 'market_routing_manifest rows are immutable');
                END;
CREATE TRIGGER trg_market_routing_manifest_immutable_delete
                BEFORE DELETE ON market_routing_manifest
                BEGIN
                    SELECT RAISE(ABORT, 'market_routing_manifest rows are immutable');
                END;
CREATE TRIGGER trg_market_update_item_immutable_insert
            BEFORE INSERT ON market_update_item
            WHEN EXISTS (
                SELECT 1
                FROM market_update_item
                WHERE
        (task_id = NEW.task_id AND ordinal = NEW.ordinal)
        OR (task_id = NEW.task_id AND symbol = NEW.symbol)

            )
            BEGIN
                SELECT RAISE(ABORT, 'market_update_item rows are immutable');
            END;
CREATE TRIGGER trg_market_update_item_immutable_update
                BEFORE UPDATE ON market_update_item
                BEGIN
                    SELECT RAISE(ABORT, 'market_update_item rows are immutable');
                END;
CREATE TRIGGER trg_market_update_item_immutable_delete
                BEFORE DELETE ON market_update_item
                BEGIN
                    SELECT RAISE(ABORT, 'market_update_item rows are immutable');
                END;
CREATE TRIGGER trg_market_update_occurrence_immutable_insert
            BEFORE INSERT ON market_update_occurrence
            WHEN EXISTS (
                SELECT 1
                FROM market_update_occurrence
                WHERE
        (schedule_id = NEW.schedule_id AND local_date = NEW.local_date)
        OR task_id = NEW.task_id

            )
            BEGIN
                SELECT RAISE(ABORT, 'market_update_occurrence rows are immutable');
            END;
CREATE TRIGGER trg_market_update_occurrence_immutable_update
