CREATE INDEX ix_analysis_model_config_list ON analysis_model_config (display_name, id);
CREATE INDEX ix_analysis_model_config_status ON analysis_model_config (status, updated_at, id);
CREATE TRIGGER trg_analysis_model_config_immutable_update BEFORE UPDATE OF id, provider, model, public_config_json, public_config_hash, secret_reference_id, supersedes_id, created_at ON analysis_model_config FOR EACH ROW WHEN NEW.id IS NOT OLD.id OR NEW.provider IS NOT OLD.provider OR NEW.model IS NOT OLD.model OR NEW.public_config_json IS NOT OLD.public_config_json OR NEW.public_config_hash IS NOT OLD.public_config_hash OR NEW.secret_reference_id IS NOT OLD.secret_reference_id OR NEW.supersedes_id IS NOT OLD.supersedes_id OR NEW.created_at IS NOT OLD.created_at BEGIN SELECT RAISE(ABORT, 'analysis model config is immutable'); END;
CREATE TRIGGER trg_analysis_model_config_initial_revision BEFORE INSERT ON analysis_model_config FOR EACH ROW WHEN NEW.revision <> 0 BEGIN SELECT RAISE(ABORT, 'model config revision must start at zero'); END;
CREATE TRIGGER trg_analysis_model_config_disabled_terminal BEFORE UPDATE ON analysis_model_config FOR EACH ROW WHEN OLD.status = 'disabled' BEGIN SELECT RAISE(ABORT, 'disabled model config is terminal'); END;
CREATE TRIGGER trg_analysis_model_config_mutation_guard BEFORE UPDATE ON analysis_model_config FOR EACH ROW WHEN NOT (NEW.id IS OLD.id AND NEW.display_name IS OLD.display_name AND NEW.provider IS OLD.provider AND NEW.model IS OLD.model AND NEW.public_config_json IS OLD.public_config_json AND NEW.public_config_hash IS OLD.public_config_hash AND NEW.secret_reference_id IS OLD.secret_reference_id AND NEW.supersedes_id IS OLD.supersedes_id AND NEW.status IS OLD.status AND NEW.revision IS OLD.revision AND NEW.verified_at IS OLD.verified_at AND NEW.last_tested_at IS OLD.last_tested_at AND NEW.error_code IS OLD.error_code AND NEW.created_at IS OLD.created_at AND NEW.updated_at IS OLD.updated_at) AND (NEW.revision <> OLD.revision + 1 OR NEW.updated_at <= OLD.updated_at OR NEW.updated_at < NEW.created_at OR (NEW.status = 'unverified' AND OLD.status <> 'unverified') OR (NEW.display_name IS OLD.display_name AND NEW.status IS OLD.status AND NEW.verified_at IS OLD.verified_at AND NEW.last_tested_at IS OLD.last_tested_at AND NEW.error_code IS OLD.error_code)) BEGIN SELECT RAISE(ABORT, 'model config mutation audit is invalid'); END;
CREATE TRIGGER trg_analysis_model_config_no_replace BEFORE INSERT ON analysis_model_config FOR EACH ROW WHEN EXISTS (SELECT 1 FROM analysis_model_config WHERE id = NEW.id) BEGIN SELECT RAISE(ABORT, 'analysis model config already exists'); END;
CREATE TRIGGER trg_analysis_model_config_no_delete BEFORE DELETE ON analysis_model_config FOR EACH ROW BEGIN SELECT RAISE(ABORT, 'analysis model config cannot be deleted'); END;
COMMIT;
